from flask import Flask, request, jsonify
from flask_oauthlib.client import OAuth2Client

app = Flask(__name__)

# Initialize the OAuth client
oauth = OAuth2Client(app)

# Define a function to validate access tokens
def validate_token(token):
    # Check if the token exists in the database
    if token not in oauth.tokens:
        return False
    
    # If the token is valid, return True
    return True

# Define an API endpoint that requires a valid access token
@app.route('/protected', methods=['GET'])
@require_oauth(validate_token)
def protected():
    # Return some data if the access token is valid
    return jsonify({'data': 'Hello, world!'})